import numpy as np
import matplotlib.pyplot as plt
from matplotlib.widgets import Slider
from matplotlib.gridspec import GridSpec


def plot_figure(positions, straylight):

    # Create figure with tree subplots
    fig = plt.figure()

    ax1 = fig.add_subplot(2,1,1)
    # Let's add the top data
    ax1.plot(straylight, "r-")
    line_light = ax1.axvline(0, color="b", linestyle="--")
    dot_light = ax1.scatter(0, straylight[0])
    ax1.set_title(f"Straylight as function of time: {straylight[0]}")
    ax1.set_xlabel("time")
    ax1.set_ylabel("photons / s")
    ax1.grid(True)



    # Let's add the positions of moon/sc/sun
    ax2 = fig.add_subplot(2, 1, 2, projection="3d")
    scatter = {}
    body_names = ["Spacecraft", "Sun", "Moon"]
    for i, body in enumerate(body_names):
        pos = positions[0][i]
        scatter[body] = ax2.plot([pos[0]], [pos[1]], [pos[2]], "o",
                                 markersize=10, label=body)[0]

    ax2.plot([0], [0], [0], "o", markersize=10, label="earth")
    ax2.set_title("3D Position of Three Bodies")
    ax2.set_xlabel("X")
    ax2.set_ylabel("Y")
    ax2.set_zlabel("Z")
    ax2.legend()

    # Slider
    plt.subplots_adjust(bottom=0.125)
    slider_ax = plt.axes([0.2, 0.05, 0.6, 0.03])
    slider = Slider(ax=slider_ax, label="Time [days]", valmin=0,
                    valmax=len(positions)-1, valinit=0, valstep=1)


    def update(val):
        # Update the straylight plot

        ax1.set_title(f"Straylight as function of time: t = {val}, \
        straylight = {straylight[val]}")
        dot_light.set_offsets(np.c_[val, straylight[val]])

        # Update the position of the sun, moon, and sc
        for i, body in enumerate(body_names):
            pos = positions[val][i]
            scatter[body].set_data([pos[0]], [pos[1]])
            scatter[body].set_3d_properties([pos[2]])

        fig.canvas.draw_idle()

    slider.on_changed(update)
    plt.show()


